You are a fix agent. Resolve the following final-review finding.

Review dimension: UI/UX
Severity: high
File: src/app.css:316-330
Title: Visible ⋮ trigger remains non-tappable on touch (pointer-events:none kept on base rule)

Finding:
The fix raised the base opacity from 0 to 0.35 specifically so touch devices 'can still perceive and tap the trigger' (per the new CSS comment), but the base `.row-menu-btn` rule still sets `pointer-events: none`. pointer-events:none blocks ALL pointer input, including touch, so on a phone/tablet the now-visible ⋮ button cannot be tapped at all. The reveal conditions that switch to `pointer-events:auto` (tr:hover, tr:focus-within, .row-menu-btn:focus-visible, [aria-expanded=true]) cannot fire without first interacting with the button — which the blocked input makes impossible. Net effect: touch users see an affordance that does nothing when tapped; the only working path is an undiscoverable long-press (contextmenu) on the row. The original critical finding's keyboard half is fixed, but the touch-operability half is not — the fix is internally inconsistent with its own stated intent.

Fix instructions (follow exactly; make targeted, minimal changes):
In src/app.css, make the ⋮ trigger directly operable on touch/coarse-pointer devices while preserving the desktop hover-to-reveal aesthetic. Add a media query such as `@media (hover: none), (pointer: coarse) { .row-menu-btn { opacity: 1; pointer-events: auto; } }` so that on devices without a hover-capable pointer the button is fully visible and tappable at rest (desktop keeps the existing reveal-on-hover behavior). Then verify, using browser touch/coarse-pointer emulation, that the ⋮ button both renders and responds to a single tap to open the dropdown. Optionally update src/app.css.test.ts to assert that a coarse-pointer reveal rule exists.

## Response Format (required)
Respond with ONLY a single valid JSON object matching the schema below.
- No prose, explanations, or commentary before or after the JSON.
- No markdown code fences (```), no headings — output the raw JSON object.
- Do NOT call any tools and do NOT end your turn on a thinking block. Emit the JSON object directly as text.

JSON schema:
{ approved: Whether the implementation is accepted, feedback: Detailed review feedback, issues: Array<{ file: File with the issue, description: What needs to be fixed, severity: "critical" | "minor" /* How important the fix is */ }> }

/**
 * Static-asset tests for `src/app.css` — guards against a subtle native-<dialog>
 * CSS regression.
 *
 * A closed `<dialog>` is hidden by the UA rule `dialog:not([open]){display:none}`.
 * But an AUTHOR `display` declaration overrides the UA stylesheet regardless of
 * specificity, so setting `display` on the base `.browser-dialog` rule keeps the
 * closed dialog (and therefore its frame/titlebar) visible on the page — the
 * "frame in the middle of the screen with no dialog open" bug.
 *
 * The contract under test:
 *   - the base `.browser-dialog { ... }` rule (selector without `[open]`) must
 *     NOT declare `display`;
 *   - the flex-column layout must live on `.browser-dialog[open]` so it only
 *     applies while the dialog is shown.
 *
 * These tests parse the raw CSS string (the vitest environment does not load
 * app.css, so `getComputedStyle` cannot observe author rules), matching the
 * approach used in `index.html.test.ts`.
 */
import { describe, it, expect, beforeAll } from 'vitest';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const CSS_PATH = resolve(__dirname, './app.css');
const CSS = readFileSync(CSS_PATH, 'utf8');

/**
 * Extract the declaration block of the FIRST rule whose selector matches the
 * given selector regex anchor, stopping at the first `}`. Returns null if no
 * such rule exists.
 *
 * `anchor` must match the selector up to (but not including) the opening brace;
 * callers pass a regex that is anchored to avoid prefix collisions (e.g. the
 * base `.browser-dialog` rule must not be confused with `.browser-dialog[open]`
 * or `.browser-dialog .dialog-body`).
 */
/**
 * Extract the declaration block of the FIRST rule (within `text`) whose
 * selector matches `selectorRegex`, stopping at the first `}`. Returns null if
 * no such rule exists.
 *
 * This is the scoped generalization of `ruleDeclarations` below (which is
 * hard-wired to the whole stylesheet); it lets us look up a rule nested inside
 * an `@media` body.
 */
function declarationsIn(text: string, selectorRegex: RegExp): string | null {
  const re = new RegExp(selectorRegex.source + '\\s*\\{([^}]*)\\}');
  const m = text.match(re);
  return m ? m[1] : null;
}

function ruleDeclarations(selectorRegex: RegExp): string | null {
  return declarationsIn(CSS, selectorRegex);
}

/**
 * Extract the body of the FIRST `@media` rule whose media-condition targets
 * coarse-pointer / touch devices — i.e. references `(hover: none)` and/or
 * `(pointer: coarse)` — correctly handling the nested `{ ... }` rule blocks
 * inside a media query (a naive "stop at the first `}`" parse returns only a
 * fragment). Returns null if no such rule exists.
 *
 * Whitespace inside the condition is normalized before matching, so both
 * `(hover: none)` and `(hover:none)` (and likewise for `pointer: coarse`) are
 * accepted. The vitest environment does not load app.css and does not set any
 * emulated media features, so this text-parsing approach is the only way to
 * observe an `@media` rule.
 */
function coarsePointerMediaQueryBody(): string | null {
  const mediaRe = /@media\s+([^{}]*)\{/g;
  let m: RegExpExecArray | null;
  while ((m = mediaRe.exec(CSS)) !== null) {
    const condition = m[1].replace(/\s+/g, '');
    const targetsTouch = condition.includes('hover:none') || condition.includes('pointer:coarse');
    if (!targetsTouch) continue;
    const start = m.index! + m[0].length;
    let depth = 1;
    let i = start;
    while (i < CSS.length && depth > 0) {
      if (CSS[i] === '{') depth++;
      else if (CSS[i] === '}') depth--;
      i++;
    }
    if (depth !== 0) return null; // unbalanced braces — treat as not found
    return CSS.slice(start, i - 1);
  }
  return null;
}

/**
 * Returns the full selector list (the text between the previous rule's closing
 * `}` and the opening `{`) of the REVEAL rule — the grouped rule whose
 * declaration block sets `opacity:1` and `pointer-events:auto`. Returns the
 * empty string if no such rule exists.
 *
 * Used to verify WHICH selectors participate in the `.row-menu-btn` reveal
 * (hover / keyboard-focus / aria-expanded) without depending on the exact
 * quote style of `[aria-expanded]`.
 */
function revealSelectorList(): string {
  const m = CSS.match(/opacity\s*:\s*1\s*;[\s\S]*?pointer-events\s*:\s*auto\s*;/);
  if (!m || m.index === undefined) return '';
  const upToDecl = CSS.slice(0, m.index);
  const openBrace = upToDecl.lastIndexOf('{');
  const prevClose = upToDecl.lastIndexOf('}', openBrace);
  return CSS.slice(prevClose + 1, openBrace);
}

/**
 * Returns the body (text between the outer `{` … `}`) of the FIRST
 * `@media (hover: none) { … }` block, or the empty string if none exists.
 * Brace-balanced so nested rules inside the media block are captured.
 *
 * Touch devices have no `:hover`, so the `.row-menu-btn` hover-based reveal is
 * unreachable there unless an author `@media (hover: none)` override (or a
 * non-zero base opacity) makes the trigger perceivable & operable.
 */
function mediaHoverNoneBody(): string {
  const open = CSS.search(/@media[^{]*\(\s*hover\s*:\s*none\s*\)[^{]*\{/);
  if (open < 0) return '';
  const braceIdx = CSS.indexOf('{', open);
  if (braceIdx < 0) return '';
  let i = braceIdx + 1;
  let depth = 1;
  let body = '';
  while (i < CSS.length && depth > 0) {
    const ch = CSS[i];
    if (ch === '{') depth++;
    else if (ch === '}') depth--;
    if (depth > 0) body += ch;
    i++;
  }
  return body;
}

describe('src/app.css — native <dialog> visibility contract', () => {
  it('the base .browser-dialog rule does NOT declare display', () => {
    // Selector must be exactly `.browser-dialog` followed by `{` — the negative
    // lookahead prevents matching `.browser-dialog[open]`, `.browser-dialog .x`,
    // or `.browser-dialog::backdrop`.
    const base = ruleDeclarations(/\.browser-dialog(?![\w[#.])/);
    expect(base, 'a base .browser-dialog { ... } rule must exist').not.toBeNull();
    expect(
      /display\s*:/.test(base!),
      'the base .browser-dialog rule must not set `display` — that would override ' +
        'the UA `dialog:not([open]){display:none}` and render the closed dialog visible',
    ).toBe(false);
  });

  it('the flex-column layout is scoped to .browser-dialog[open]', () => {
    const open = ruleDeclarations(/\.browser-dialog\[open\]/);
    expect(open, 'a .browser-dialog[open] { ... } rule must exist').not.toBeNull();
    expect(/display\s*:\s*flex/.test(open!), 'open dialog must use display:flex').toBe(true);
    expect(/flex-direction\s*:\s*column/.test(open!), 'open dialog must be a flex column').toBe(
      true,
    );
  });
});

/* ===========================================================================
 * Upload control — keyboard accessibility contract
 *
 * The file input is visually hidden via a `visually-hidden` (sr-only) class
 * instead of the `hidden` HTML attribute, precisely so it STAYS in the tab
 * order and is keyboard-focusable (the `hidden` attribute's UA `display:none`
 * made Upload unreachable via keyboard — WCAG 2.1.1). These tests pin the
 * CSS half of that contract by parsing the raw stylesheet:
 *
 *   - `.visually-hidden` must use the standard clip-to-1x1 sr-only pattern
 *     (position:absolute + width/height:1px + clip:rect(0,0,0,0) + overflow:
 *     hidden + white-space:nowrap). Crucially it must NOT use `display:none`
 *     NOR `visibility:hidden` — both of which remove an element from the tab
 *     order and would re-introduce the exact bug the class exists to avoid.
 *   - `.toolbar label.btn:focus-within` must apply a visible focus indicator
 *     so a sighted keyboard user can see that focus has landed on the Upload
 *     button (the input itself is clipped to 1x1, so its own focus outline is
 *     not a reliable signal; the wrapping label must reflect the focus).
 *
 * As above, the raw CSS is parsed because the vitest environment does not load
 * app.css, so `getComputedStyle` cannot observe author rules.
 * ========================================================================= */
describe('src/app.css — upload control keyboard accessibility', () => {
  describe('.visually-hidden uses the sr-only clip pattern (NOT display:none / visibility:hidden)', () => {
    it('a .visually-hidden rule exists', () => {
      // Negative lookahead so `.visually-hidden` is not confused with a
      // hypothetical `.visually-hidden-something` descendant/compound selector.
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/);
      expect(rule, 'a .visually-hidden { ... } rule must exist').not.toBeNull();
    });

    it('positions the element absolutely and clips it to a 1x1 box (sr-only pattern)', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      expect(/position\s*:\s*absolute/.test(rule), 'position:absolute').toBe(true);
      expect(/width\s*:\s*1px/.test(rule), 'width:1px').toBe(true);
      expect(/height\s*:\s*1px/.test(rule), 'height:1px').toBe(true);
      expect(/overflow\s*:\s*hidden/.test(rule), 'overflow:hidden').toBe(true);
      expect(/clip\s*:\s*rect\(/.test(rule), 'clip:rect(...)').toBe(true);
      expect(/white-space\s*:\s*nowrap/.test(rule), 'white-space:nowrap').toBe(true);
    });

    it('collapses padding/margin/border so the 1x1 box carries no visible footprint', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      expect(/padding\s*:\s*0/.test(rule), 'padding:0').toBe(true);
      expect(/border\s*:\s*0/.test(rule), 'border:0').toBe(true);
      // margin is typically -1px to pull the 1x1 box fully out of flow.
      expect(/margin\s*:\s*-1px/.test(rule), 'margin:-1px').toBe(true);
    });

    it('does NOT use display:none (which would re-introduce the keyboard-inaccessibility bug)', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      expect(
        /display\s*:\s*none/.test(rule),
        'visually-hidden must NOT use display:none — that removes the element from ' +
          'the tab order, which is exactly the keyboard failure the class exists to avoid',
      ).toBe(false);
    });

    it('does NOT use visibility:hidden (which also ejects the element from the tab order)', () => {
      const rule = ruleDeclarations(/\.visually-hidden(?![\w[#.:])/)!;
      // `visibility:hidden` has the same effect as `display:none` for keyboard
      // access: an element with `visibility:hidden` cannot receive focus and is
      // removed from the sequential focus order. The classic sr-only clip
      // pattern intentionally omits it (it clips with `overflow:hidden` +
      // `clip:rect(0,0,0,0)` instead), so its presence would re-introduce the
      // exact bug the class exists to fix.
      expect(
        /visibility\s*:\s*hidden/.test(rule),
        'visually-hidden must NOT use visibility:hidden — like display:none, an element ' +
          'with visibility:hidden is removed from the tab order and cannot receive focus',
      ).toBe(false);
    });
  });

  describe('.toolbar label.btn shows a visible focus ring when its input is focused', () => {
    it('a .toolbar label.btn:focus-within rule exists', () => {
      const rule = ruleDeclarations(/\.toolbar\s+label\.btn:focus-within/);
      expect(
        rule,
        'a .toolbar label.btn:focus-within { ... } rule must exist so the Upload ' +
          'button shows focus when the (clipped) input inside it receives keyboard focus',
      ).not.toBeNull();
    });

    it('applies a visible focus indicator (outline/border/box-shadow)', () => {
      const rule = ruleDeclarations(/\.toolbar\s+label\.btn:focus-within/)!;
      // Accept any of the common visible focus indicators. `outline: none` does
      // NOT count (it suppresses the indicator); a real outline value does.
      const hasOutline = /outline\s*:\s*(?!none\b)/.test(rule);
      const hasBorder = /border\s*:\s*(?!none\b)/.test(rule);
      const hasBoxShadow = /box-shadow\s*:\s*(?!none\b)/.test(rule);
      const hasBackground = /background\s*:\s*(?!none\b)/.test(rule);
      expect(
        hasOutline || hasBorder || hasBoxShadow || hasBackground,
        ':focus-within must set a visible focus indicator ' +
          '(a non-none outline/border/box-shadow/background)',
      ).toBe(true);
    });
  });
});

/* ===========================================================================
 * Browse table — per-row action menu & browse-only column alignment
 *
 * The browse table carries `browse-table` IN ADDITION to the shared
 * `results-table` class. It renders a per-row "⋮" button (`.row-menu-btn`)
 * that opens a fixed-position dropdown (`.row-menu`) of `<button class="btn">`
 * / `<a class="btn">` action items. These tests pin the CSS contract for those
 * pieces plus the browse-only column alignment. As above, they parse the raw
 * stylesheet because the vitest environment does not load app.css.
 *
 * Critical gotcha re-tested below (the SAME class of bug already documented for
 * `.browser-dialog`): `.row-menu` closes via the HTML `hidden` attribute (UA
 * `[hidden]{display:none}`), but the AUTHOR `.row-menu{display:flex}` rule would
 * override the UA sheet and keep a closed menu visible on screen. An explicit,
 * higher-specificity `.row-menu[hidden]{display:none}` override MUST exist.
 * ========================================================================= */
describe('src/app.css — browse table column alignment (scoped to .browse-table)', () => {
  it('stretches the Name column (1st) to absorb the remaining table width', () => {
    // width:100% on column 1 + the table being width:100% / table-layout:auto
    // with nowrap cells means the other (content-width) columns hold their size
    // and Name takes the remainder — the "flex:1-like" stretch for col 1.
    const col1 = ruleDeclarations(/\.browse-table td:nth-child\(1\)/);
    expect(col1, 'a .browse-table column-1 rule (td:nth-child(1)) must exist').not.toBeNull();
    expect(/width\s*:\s*100%/.test(col1!), 'column 1 must set width:100%').toBe(true);
    // The header cell must be covered too, not only the body cell.
    expect(CSS, 'column-1 rule must also target th:nth-child(1)').toContain(
      '.browse-table th:nth-child(1)',
    );
  });

  it('right-aligns Size, Modified, Actions (columns 2-4) for header and body cells', () => {
    // A single grouped rule lists th+td for columns 2,3,4 and sets
    // text-align:right. We anchor on the LAST selector (td:nth-child(4)) so the
    // helper captures this group rule's declaration block.
    const rightAlign = ruleDeclarations(/\.browse-table td:nth-child\(4\)/);
    expect(
      rightAlign,
      'a .browse-table right-align rule ending in td:nth-child(4) must exist',
    ).not.toBeNull();
    expect(
      /text-align\s*:\s*right/.test(rightAlign!),
      'columns 2-4 must set text-align:right',
    ).toBe(true);
    // The selector must enumerate th+td for each of columns 2, 3 and 4.
    for (const n of [2, 3, 4]) {
      expect(CSS, `column ${n} header cell must be targeted`).toContain(
        `.browse-table th:nth-child(${n})`,
      );
      expect(CSS, `column ${n} body cell must be targeted`).toContain(
        `.browse-table td:nth-child(${n})`,
      );
    }
  });

  it('does NOT alter the shared search table: global .results-table cells stay left-aligned', () => {
    // The search table only has `results-table` (no `browse-table`), so its
    // columns must keep the global text-align:left. This guards against the
    // right-align being accidentally scoped to bare `.results-table`.
    const cells = ruleDeclarations(/\.results-table td/);
    expect(cells, 'the global .results-table td rule must still exist').not.toBeNull();
    expect(/text-align\s*:\s*left/.test(cells!), 'search-table cells stay text-align:left').toBe(
      true,
    );
  });
});

describe('src/app.css — row action "⋮" button (.row-menu-btn)', () => {
  it('is a chromeless, muted, clickable button with compact sizing', () => {
    const btn = ruleDeclarations(/\.row-menu-btn/);
    expect(btn, 'a base .row-menu-btn { ... } rule must exist').not.toBeNull();
    expect(/background\s*:\s*none/.test(btn!), 'background:none').toBe(true);
    expect(/border\s*:\s*none/.test(btn!), 'border:none').toBe(true);
    expect(/color\s*:\s*#9a9a9a/.test(btn!), 'muted foreground #9a9a9a').toBe(true);
    expect(/cursor\s*:\s*pointer/.test(btn!), 'cursor:pointer').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(btn!), 'border-radius:4px').toBe(true);
    expect(/font-size\s*:\s*16px/.test(btn!), 'font-size:16px').toBe(true);
    expect(/line-height\s*:\s*1/.test(btn!), 'line-height:1').toBe(true);
    // modest padding (e.g. 2px 6px); assert it is present and pixel-based.
    expect(/padding\s*:\s*\d+px/.test(btn!), 'padding present').toBe(true);
  });

  it('is initially suppressed (low opacity, non-interactive) by default', () => {
    // The base rule keeps the trigger quiet until the row is hovered/focused or
    // its menu is open: `pointer-events:none` stops it capturing clicks while
    // idle, and the opacity is driven to a LOW (0 or faint) value. The exact
    // idle opacity is implementation-defined (see the touch-reachability test
    // below) — it may stay 0 (hidden, revealed only by interaction) or be lifted
    // to a faint non-zero value so touch users can perceive it — but it must NOT
    // be fully opaque at rest.
    const btn = ruleDeclarations(/\.row-menu-btn/)!;
    expect(/pointer-events\s*:\s*none/.test(btn), 'pointer-events:none by default').toBe(true);
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'base opacity suppresses visibility (< 1) at rest').toBeLessThan(1);
  });

  it('becomes visible + interactive on row hover and when its menu is open', () => {
    // The grouped reveal rule covers both conditions; anchor on the
    // [aria-expanded="true"] selector which is the last one before the brace.
    const reveal = ruleDeclarations(/\.row-menu-btn\[aria-expanded=['"]true['"]\]/);
    expect(reveal, 'a reveal rule covering [aria-expanded="true"] must exist').not.toBeNull();
    expect(/opacity\s*:\s*1/.test(reveal!), 'revealed opacity:1').toBe(true);
    expect(/pointer-events\s*:\s*auto/.test(reveal!), 'revealed pointer-events:auto').toBe(true);
    // Row-hover must also be one of the reveal selectors.
    expect(CSS, 'hover reveal must include the browse row-hover selector').toContain(
      '.browse-table tbody tr:hover .row-menu-btn',
    );
  });

  it('brightens to full foreground on its own hover', () => {
    const hover = ruleDeclarations(/\.row-menu-btn:hover/);
    expect(hover, 'a .row-menu-btn:hover rule must exist').not.toBeNull();
    expect(/color\s*:\s*#e6e6e6/.test(hover!), 'hover color #e6e6e6').toBe(true);
  });

  /* ── Accessibility fix: keyboard focus & touch reachability ──
     The trigger was opacity:0 + pointer-events:none by default and revealed
     ONLY by `tr:hover` / `[aria-expanded="true"]`. That left it (1) with NO
     visible focus indicator for keyboard users (WCAG 2.4.7 / 2.1.1) and (2)
     completely unreachable on touch devices, which have no :hover (WCAG
     2.5.1 / 2.5.8). The tests below pin the CSS contract that fixes both. */
  it('becomes visible + interactive on keyboard focus, not only on hover/open', () => {
    // The reveal rule (opacity:1 + pointer-events:auto) must include a
    // keyboard-focus selector — :focus-visible on the button and/or
    // :focus-within on the row — so a keyboard user sees & can operate it.
    const selectors = revealSelectorList();
    expect(
      selectors.length,
      'a reveal rule (opacity:1 + pointer-events:auto) must exist',
    ).toBeGreaterThan(0);
    const hasFocusReveal =
      selectors.includes('.row-menu-btn:focus-visible') || selectors.includes('tr:focus-within');
    expect(
      hasFocusReveal,
      'the reveal rule must include a keyboard-focus selector ' +
        '(.row-menu-btn:focus-visible and/or .browse-table tbody tr:focus-within .row-menu-btn) ' +
        'so keyboard users see & can operate the trigger',
    ).toBe(true);
  });

  it('shows a visible focus ring on keyboard focus (.row-menu-btn:focus-visible)', () => {
    // A keyboard user tabbing to the trigger must see where focus landed. The
    // grouped reveal selector `.row-menu-btn:focus-visible,` ends in a comma, so
    // ruleDeclarations (which requires the selector to sit immediately before
    // `{`) matches only the STANDALONE focus-ring rule, not the grouped reveal.
    const ring = ruleDeclarations(/\.row-menu-btn:focus-visible/);
    expect(
      ring,
      'a .row-menu-btn:focus-visible { ... } rule must exist to draw a focus ring',
    ).not.toBeNull();
    expect(
      /outline\s*:\s*(?!none\b)/.test(ring!),
      ':focus-visible must set a visible outline (not outline:none)',
    ).toBe(true);
    expect(
      /outline-offset\s*:/.test(ring!),
      ':focus-visible should set outline-offset so the ring clears the button box',
    ).toBe(true);
  });

  it('is reachable on touch devices (no :hover): faintly visible by default OR a @media (hover:none) reveal', () => {
    // Touch devices have no :hover, so the hover-based reveal never fires and
    // the whole row-actions feature would be unreachable. The trigger must be
    // perceivable & operable without a hover-capable pointer. Either of these
    // satisfies the contract:
    //   (a) a faint-but-non-zero base opacity (button at least visible at rest), or
    //   (b) a @media (hover: none) block that reveals the button
    //       (opacity + pointer-events:auto) on hover-incapable devices.
    const base = ruleDeclarations(/\.row-menu-btn/)!;
    const op = base.match(/opacity\s*:\s*([0-9.]+)/);
    const faintlyVisibleByDefault = !!op && Number(op[1]) > 0;

    const mediaBody = mediaHoverNoneBody();
    const mediaRevealsOnTouch =
      /\.row-menu-btn/.test(mediaBody) &&
      /opacity\s*:/.test(mediaBody) &&
      /pointer-events\s*:\s*auto/.test(mediaBody);

    expect(
      faintlyVisibleByDefault || mediaRevealsOnTouch,
      'on touch (no :hover) the trigger must be perceivable & operable: either a ' +
        'non-zero base opacity OR a @media (hover:none) reveal of the button',
    ).toBe(true);
  });
});

/* ===========================================================================
 * Row menu "⋮" trigger — hit-area / target SIZE (WCAG 2.5.8 Target Size Minimum)
 *
 * Even once the trigger is made perceivable & operable (the focus/touch fixes
 * covered above), its tappable box must be large enough to hit accurately. The
 * base rule historically rendered at ~20px tall × ~28px wide (padding 2px 6px,
 * font-size 16px, line-height 1), which is BELOW the WCAG 2.5.8 (AA) 24×24 CSS-px
 * minimum target size — and well below the 2.5.5 (AAA) / platform 44×44 guidance.
 * For a hover-gated trigger this is doubly punishing on touch, so the hit area
 * is enlarged to >= 24×24 (preferably ~32px) by raising the padding and adding
 * explicit min-width / min-height, WITHOUT changing the glyph's visual size
 * (font-size/line-height stay 16px / 1) and without regressing the chromeless
 * look or the opacity/pointer-events reveal behavior.
 *
 * As throughout this file the raw stylesheet is parsed (the vitest env does not
 * load app.css, so getComputedStyle cannot observe author rules). We read the
 * numeric min-width / min-height and compute the rendered box height from
 * font-size × line-height + vertical padding, asserting each axis >= 24px.
 * ========================================================================= */
describe('src/app.css — "⋮" trigger hit area meets WCAG 2.5.8 minimum (>= 24×24)', () => {
  const WCAG_AA_MIN = 24; // CSS px, WCAG 2.5.8 (AA) Target Size Minimum

  /**
   * Read the value (in px) of a `prop: <n>px` declaration on a rule block.
   * Anchored on a preceding start-of-block or `;` so a prop name cannot match a
   * suffix of another property (e.g. `min-width` will never match `max-width`).
   * Returns null when the property is absent.
   */
  function pxValue(decls: string, prop: string): number | null {
    const re = new RegExp(`(?:^|;)\\s*${prop}\\s*:\\s*([0-9]+)px`, 'm');
    const m = decls.match(re);
    return m ? Number(m[1]) : null;
  }

  /** First (vertical) value of a `padding: <v>px [<h>px]?` declaration. */
  function verticalPaddingPx(decls: string): number {
    const m = decls.match(/padding\s*:\s*([0-9]+)px(?:\s+[0-9]+px)?/);
    return m ? Number(m[1]) : 0;
  }

  let btn: string;
  beforeAll(() => {
    btn = ruleDeclarations(/\.row-menu-btn/)!;
    expect(btn, 'a base .row-menu-btn { ... } rule must exist').not.toBeNull();
  });

  it('declares a min-width >= 24px so the box is never narrower than the minimum', () => {
    const mw = pxValue(btn, 'min-width');
    expect(mw, '.row-menu-btn must declare a px min-width (floor on tap width)').not.toBeNull();
    expect(mw!, 'min-width must be >= 24px (WCAG 2.5.8 AA)').toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('declares a min-height >= 24px so the box is never shorter than the minimum', () => {
    const mh = pxValue(btn, 'min-height');
    expect(mh, '.row-menu-btn must declare a px min-height (floor on tap height)').not.toBeNull();
    expect(mh!, 'min-height must be >= 24px (WCAG 2.5.8 AA)').toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('renders a box >= 24px tall from font-size × line-height + vertical padding', () => {
    // The trigger's content height is line-height(1) × font-size, grown by the
    // vertical padding; the box height is the max of that and min-height. This
    // pins the EFFECTIVE hit height regardless of which mechanism delivers it.
    const fontSize = pxValue(btn, 'font-size') ?? 0;
    const lh = btn.match(/line-height\s*:\s*([0-9.]+)/);
    const lineHeight = lh ? Number(lh[1]) : 1; // unitless multiplier; default 1
    const minH = pxValue(btn, 'min-height') ?? 0;
    const boxHeight = Math.max(fontSize * lineHeight + verticalPaddingPx(btn) * 2, minH);
    expect(
      boxHeight,
      `rendered hit-box height must be >= 24px (got ${boxHeight}px from font-size ${fontSize}px, ` +
        `line-height ${lineHeight}, padding ${verticalPaddingPx(btn)}px, min-height ${minH}px)`,
    ).toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('keeps the visual glyph size unchanged while enlarging the target', () => {
    // The hit-area fix must NOT change the glyph itself: font-size stays 16px
    // and line-height stays 1.
    expect(pxValue(btn, 'font-size'), 'font-size stays 16px (glyph not resized)').toBe(16);
    expect(btn, 'line-height stays 1').toMatch(/line-height\s*:\s*1\s*;/);
  });

  it('preserves the chromeless look and idle reveal behavior after enlarging', () => {
    // The size change must not regress the other base-rule contracts.
    expect(/background\s*:\s*none/.test(btn), 'background:none preserved').toBe(true);
    expect(/border\s*:\s*none/.test(btn), 'border:none preserved').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(btn), 'border-radius:4px preserved').toBe(true);
    expect(/cursor\s*:\s*pointer/.test(btn), 'cursor:pointer preserved').toBe(true);
    expect(/pointer-events\s*:\s*none/.test(btn), 'pointer-events:none at rest preserved').toBe(
      true,
    );
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'opacity stays suppressed (<1) at rest').toBeLessThan(1);
  });
});

/* ===========================================================================
 * Row action "⋮" button — touch / coarse-pointer operability
 *
 * The base `.row-menu-btn` rule keeps the trigger suppressed at rest
 * (`opacity: 0.35; pointer-events: none`) and reveals it only via row hover,
 * keyboard focus, or an open popup. That is a desktop aesthetic that assumes a
 * precise, hover-capable pointer — and it is DEAD on a touch device:
 * `pointer-events: none` blocks ALL pointer input (including touch taps), so a
 * phone/tablet user can SEE the faintly-visible ⋮ but cannot tap it, and the
 * reveal conditions (which require first interacting with the button or its
 * row) can never fire (WCAG 2.5.1 / 2.5.8).
 *
 * The fix contract pinned here: a `(hover: none)` / `(pointer: coarse)` media
 * query lifts the button to fully visible AND tappable AT REST on devices
 * without a hover-capable pointer, while desktop keeps the reveal-on-hover
 * behavior (the base rule is unchanged — still tested above). The crux is
 * `pointer-events: auto` inside that media query; `opacity: 1` is the matching
 * visibility half.
 * ========================================================================= */
describe('src/app.css — row action "⋮" button touch operability (coarse pointer)', () => {
  it('defines an @media rule targeting coarse-pointer / touch devices', () => {
    const body = coarsePointerMediaQueryBody();
    expect(
      body,
      'an @media rule targeting (hover: none) and/or (pointer: coarse) must exist so the ' +
        '⋮ button is operable on touch devices that have no hover-capable pointer',
    ).not.toBeNull();
  });

  it('makes the ⋮ button fully visible (opacity:1) at rest on touch', () => {
    const body = coarsePointerMediaQueryBody();
    expect(body, 'a coarse-pointer media query must exist').not.toBeNull();
    const btn = declarationsIn(body!, /\.row-menu-btn(?![\w[#.:])/);
    expect(
      btn,
      'a .row-menu-btn rule must exist inside the coarse-pointer media query',
    ).not.toBeNull();
    expect(/opacity\s*:\s*1/.test(btn!), 'opacity:1 at rest on touch').toBe(true);
  });

  it('makes the ⋮ button directly tappable (pointer-events:auto) at rest on touch', () => {
    // This is the crux of the touch bug: the base rule sets pointer-events:none,
    // which blocks ALL pointer input (including touch taps). On a coarse-pointer
    // device the button MUST be pointer-events:auto AT REST — otherwise it is
    // visible-but-dead and the hover/focus reveal conditions can never fire
    // (there is no way to first "reveal" something whose input is blocked).
    const body = coarsePointerMediaQueryBody();
    expect(body, 'a coarse-pointer media query must exist').not.toBeNull();
    const btn = declarationsIn(body!, /\.row-menu-btn(?![\w[#.:])/);
    expect(
      btn,
      'a .row-menu-btn rule must exist inside the coarse-pointer media query',
    ).not.toBeNull();
    expect(
      /pointer-events\s*:\s*auto/.test(btn!),
      'pointer-events:auto at rest on touch (the base pointer-events:none would block taps)',
    ).toBe(true);
  });

  it('does not regress the desktop base rule (still suppressed at rest)', () => {
    // The touch fix must be ADDITIVE — a media-query override — not a change to
    // the base rule, so desktop keeps its reveal-on-hover aesthetic. The base
    // rule must still set pointer-events:none and an opacity < 1 at rest.
    const btn = ruleDeclarations(/\.row-menu-btn(?![\w[#.:])/)!;
    expect(/pointer-events\s*:\s*none/.test(btn), 'base pointer-events:none unchanged').toBe(true);
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'base opacity stays < 1 at rest on desktop').toBeLessThan(1);
  });
});

describe('src/app.css — row action dropdown menu (.row-menu)', () => {
  it('is a fixed-position, flex-column overlay that floats above the scroll container', () => {
    const menu = ruleDeclarations(/\.row-menu/);
    expect(menu, 'a base .row-menu { ... } rule must exist').not.toBeNull();
    // position:fixed so a menu placed at viewport clientX/clientY is NOT clipped
    // by the .results{overflow:auto} scroll container and layers correctly.
    expect(/position\s*:\s*fixed/.test(menu!), 'position:fixed').toBe(true);
    // Must sit above the sticky th (which has z-index:1).
    const z = menu!.match(/z-index\s*:\s*(\d+)/);
    expect(z, 'z-index declared').not.toBeNull();
    expect(Number(z![1]), 'z-index must be > 1 to sit above the sticky th').toBeGreaterThan(1);
    expect(/display\s*:\s*flex/.test(menu!), 'display:flex').toBe(true);
    expect(/flex-direction\s*:\s*column/.test(menu!), 'flex-direction:column').toBe(true);
    expect(/min-width\s*:\s*140px/.test(menu!), 'min-width:140px').toBe(true);
    expect(/box-shadow\s*:/.test(menu!), 'box-shadow present').toBe(true);
    expect(/background\s*:\s*#2d2d30/.test(menu!), 'background:#2d2d30').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(menu!), 'border-radius:4px').toBe(true);
  });

  it('is actually hidden when [hidden] despite the author display:flex (critical override)', () => {
    // Same class of bug as .browser-dialog above: the menu closes via the HTML
    // `hidden` attribute (UA [hidden]{display:none}), but the author
    // `.row-menu{display:flex}` rule overrides the UA sheet and would keep a
    // closed menu visible. An explicit `.row-menu[hidden]{display:none}` rule
    // (higher specificity than the base) MUST exist to defeat that.
    const hidden = ruleDeclarations(/\.row-menu\[hidden\]/);
    expect(hidden, 'a .row-menu[hidden] { ... } override rule must exist').not.toBeNull();
    expect(/display\s*:\s*none/.test(hidden!), '.row-menu[hidden] must set display:none').toBe(
      true,
    );
  });
});

